    {
      "path": "src/App.tsx",
      "content": "import { useMemo, useState } from 'react';

type Page = 'Overview' | 'Routing Lab' | 'Eval Report';

type Candidate = {
  name: string;
  quality: number;
  latencyMs: number;
  costPer1k: number;
  alpha: number;
  beta: number;
};

const candidates: Candidate[] = [
  {
    name: 'gpt-5.3-codex',
    quality: 91.8,
    latencyMs: 1020,
    costPer1k: 0.024,
    alpha: 7.2,
    beta: 1.6
  },
  {
    name: 'gpt-5.4-mini',
    quality: 89.6,
    latencyMs: 640,
    costPer1k: 0.013,
    alpha: 9.4,
    beta: 2.1
  },
  {
    name: 'gpt-5.4-nano',
    quality: 84.9,
    latencyMs: 310,
    costPer1k: 0.004,
    alpha: 12.7,
    beta: 3.8
  }
];

export default function App() {
  const [page, setPage] = useState<Page>('Overview');
  const [traffic, setTraffic] = useState(65);

  const totals = useMemo(() => {
    const passRate = 92.4;
    const avgLatency = Math.round(
      candidates.reduce((sum, c) => sum + c.latencyMs, 0) / candidates.length
    );
    const avgCost = (
      candidates.reduce((sum, c) => sum + c.costPer1k, 0) / candidates.length
    ).toFixed(3);

    return {
      passRate,
      avgLatency,
      avgCost
    };
  }, []);

  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div className="brand">
          <div className="brand-dot" />
          <div>
            <h1>Agent Sam</h1>
            <p>Command Center</p>
          </div>
        </div>
        <nav>
          {(['Overview', 'Routing Lab', 'Eval Report'] as Page[]).map((item) => (
            <button
              key={item}
              className={`nav-btn ${page === item ? 'active' : ''}`}
              onClick={() => setPage(item)}
            >
              {item}
            </button>
          ))}
        </nav>
        <div className="side-note">
          <h4>Thompson Router</h4>
          <p>Adaptive exploration for model selection and cost-aware quality tuning.</p>
        </div>
      </aside>

      <main className="content">
        <section className="hero">
          <div>
            <h2>Agent Sam Command Center</h2>
            <p>
              Monitor routing performance, inspect alpha/beta confidence signals, and ship
              faster model decisions.
            </p>
          </div>
          <div className="hero-badge">Live Simulation</div>
        </section>

        {page === 'Overview' && (
          <section className="grid three">
            <MetricCard title="Pass Rate" value={`${totals.passRate}%`} trend="+1.8%" />
            <MetricCard title="Avg Latency" value={`${totals.avgLatency} ms`} trend="-72 ms" />
            <MetricCard title="Avg Cost / 1K" value={`$${totals.avgCost}`} trend="-11%" />

            <div className="card wide">
              <h3>Model Candidates</h3>
              <div className="chips">
                {candidates.map((c) => (
                  <span key={c.name} className="chip">
                    {c.name}
                  </span>
                ))}
              </div>
              <p className="muted">Current strategy favors mini during peak load, codex for high-complexity prompts.</p>
            </div>

            <div className="card wide">
              <h3>Thompson Sampling Snapshot</h3>
              <div className="rows">
                {candidates.map((c) => (
                  <div key={c.name} className="row">
                    <span>{c.name}</span>
                    <span>
                      α {c.alpha.toFixed(1)} / β {c.beta.toFixed(1)}
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </section>
        )}

        {page === 'Routing Lab' && (
          <section className="grid two">
            <div className="card">
              <h3>Traffic Split Simulator</h3>
              <p className="muted">Adjust exploration pressure between premium and low-latency models.</p>
              <label htmlFor="traffic">Mini/Codex Preference: {traffic}%</label>
              <input
                id="traffic"
                type="range"
                min={0}
                max={100}
                value={traffic}
                onChange={(e) => setTraffic(Number(e.target.value))}
              />
              <div className="rows compact">
                <div className="row">
                  <span>gpt-5.4-mini</span>
                  <span>{traffic}%</span>
                </div>
                <div className="row">
                  <span>gpt-5.3-codex</span>
                  <span>{Math.max(0, 100 - traffic - 15)}%</span>
                </div>
                <div className="row">
                  <span>gpt-5.4-nano</span>
                  <span>15%</span>
                </div>
              </div>
            </div>

            <div className="card">
              <h3>Routing Health</h3>
              <div className="rows compact">
                <div className="row"><span>Estimated pass rate</span><strong>{(88 + traffic * 0.08).toFixed(1)}%</strong></div>
                <div className="row"><span>Estimated latency</span><strong>{(760 - traffic * 2.1).toFixed(0)} ms</strong></div>
                <div className="row"><span>Estimated cost / 1K</span><strong>${(0.019 - traffic * 0.00007).toFixed(3)}</strong></div>
              </div>
              <p className="muted">Higher mini allocation lowers latency while preserving quality in most eval buckets.</p>
            </div>
          </section>
        )}

        {page === 'Eval Report' && (
          <section className="grid one">
            <div className="card">
              <h3>Eval Summary (Last 24h)</h3>
              <table>
                <thead>
                  <tr>
                    <th>Model</th>
                    <th>Pass Rate</th>
                    <th>Latency</th>
                    <th>Cost / 1K</th>
                    <th>Alpha / Beta</th>
                  </tr>
                </thead>
                <tbody>
                  {candidates.map((c) => (
                    <tr key={c.name}>
                      <td>{c.name}</td>
                      <td>{c.quality}%</td>
                      <td>{c.latencyMs} ms</td>
                      <td>${c.costPer1k.toFixed(3)}</td>
                      <td>
                        {c.alpha.toFixed(1)} / {c.beta.toFixed(1)}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </section>
        )}
      </main>
    </div>
  );
}

function MetricCard({ title, value, trend }: { title: string; value: string; trend: string }) {
  return (
    <div className="card metric">
      <p>{title}</p>
      <h3>{value}</h3>
      <span>{trend}</span>
    </div>
  );
}
"
    },
    {
      "path": "src/App.css",
      "content": ":root {
  font-family: Inter, ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Arial, sans-serif;
  color: #e9eefb;
  background: #0b1020;
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  background: radial-gradient(circle at 15% 15%, #1f2a4d 0%, #0b1020 45%, #080c18 100%);
  min-height: 100vh;
}

.app-shell {
  display: grid;
  grid-template-columns: 250px 1fr;
  min-height: 100vh;
}

.sidebar {
  border-right: 1px solid rgba(255, 255, 255, 0.08);
  padding: 1.2rem;
  background: rgba(8, 12, 24, 0.75);
  backdrop-filter: blur(8px);
}

.brand {
  display: flex;
  align-items: center;
  gap: 0.7rem;
  margin-bottom: 1.2rem;
}

.brand h1 {
  font-size: 1rem;
  margin: 0;
}

.brand p {
  margin: 0;
  color: #9fb0d8;
  font-size: 0.8rem;
}

.brand-dot {
  width: 12px;
  height: 12px;
  border-radius: 50%;
  background: linear-gradient(135deg, #5eead4, #6366f1);
  box-shadow: 0 0 16px rgba(94, 234, 212, 0.8);
}

nav {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.nav-btn {
  text-align: left;
  border: 1px solid rgba(255, 255, 255, 0.12);
  background: rgba(255, 255, 255, 0.03);
  color: #dfe8ff;
  padding: 0.6rem 0.7rem;
  border-radius: 10px;
  cursor: pointer;
}

.nav-btn.active {
  background: linear-gradient(135deg, rgba(99, 102, 241, 0.35), rgba(20, 184, 166, 0.25));
  border-color: rgba(255, 255, 255, 0.2);
}

.side-note {
  margin-top: 1.2rem;
  padding: 0.8rem;
  border-radius: 12px;
  background: rgba(255, 255, 255, 0.03);
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.side-note h4 {
  margin: 0 0 0.3rem;
}

.side-note p {
  margin: 0;
  color: #aab7d6;
  font-size: 0.84rem;
}

.content {
  padding: 1.4rem;
}

.hero {
  background: linear-gradient(120deg, rgba(56, 189, 248, 0.18), rgba(99, 102, 241, 0.28), rgba(16, 185, 129, 0.2));
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 16px;
  padding: 1rem 1.2rem;
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  align-items: center;
}

.hero h2 {
  margin: 0 0 0.3rem;
}

.hero p {
  margin: 0;
  color: #d3def6;
}

.hero-badge {
  padding: 0.45rem 0.7rem;
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.16);
  border: 1px solid rgba(255, 255, 255, 0.25);
  font-size: 0.82rem;
}

.grid {
  margin-top: 1rem;
  display: grid;
  gap: 1rem;
}

.grid.three {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.grid.two {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.grid.one {
  grid-template-columns: 1fr;
}

.card {
  background: rgba(255, 255, 255, 0.035);
  border: 1px solid rgba(255, 255, 255, 0.12);
  border-radius: 14px;
  padding: 1rem;
}

.card.wide {
  grid-column: span 3;
}

.metric h3 {
  margin: 0.2rem 0;
  font-size: 1.5rem;
}

.metric p,
.metric span,
.muted {
  color: #9fb0d8;
}

.rows {
  display: grid;
  gap: 0.5rem;
}

.rows.compact .row {
  padding: 0.45rem 0;
}

.row {
  display: flex;
  justify-content: space-between;
  border-bottom: 1px dashed rgba(255, 255, 255, 0.12);
  padding-bottom: 0.5rem;
}

.chips {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin: 0.7rem 0;
}

.chip {
  background: rgba(59, 130, 246, 0.2);
  border: 1px solid rgba(147, 197, 253, 0.35);
  border-radius: 999px;
  padding: 0.25rem 0.55rem;
  font-size: 0.8rem;
}

input[type='range'] {
  width: 100%;
  margin: 0.6rem 0 0.9rem;
}

table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.92rem;
}

th,
td {
  text-align: left;
  padding: 0.65rem 0.45rem;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

th {
  color: #a8b7d8;
  font-weight: 600;
}

@media (max-width: 980px) {
  .app-shell {
    grid-template-columns: 1fr;
  }

  .sidebar {
    border-right: none;
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
  }

  nav {
    flex-direction: row;
    flex-wrap: wrap;
  }

  .grid.three,
  .grid.two {
    grid-template-columns: 1fr;
  }

  .card.wide {
    grid-column: span 1;
  }
}
